select:
SELECT DOMASTER.DONG , DOMASTER.SIL , DOMASTER.SIL2 , SGCHAKCM.SORTKEY , SHJHAKJM.HAKGWA , DOMASTER.HAKYEON , DOMASTER.HAKBUN , SHJHAKJM.IRUM , DOMASTER.DORMGBN , DECODE(DOMASTER.SEX, '1', '남', '2', '여') AS SEX , DOMASTER.IPGBN , SGCHAKCM.HAKGWAFNM , SHJADDRM.HSPOSTJUSO ||' '||SHJADDRM.HSJUSO AS HSPOSTJUSO , SHJADDRM.HSJUSO , DOMASTER.STATE , SGCCODEM.CDFNM AS HJSTATE , SUBSTR(EAGLE.SHJHAKJM.JUMINNO, 1, 6) AS JUMINNO , DOMASTER.BJUMSU , DOMASTER.BANKACC , SHJADDRM.HSTEL , SHJADDRM.HSBBTEL , DOMASTER.SEQ FROM EAGLE.DOMASTER DOMASTER , EAGLE.SHJADDRM SHJADDRM , EAGLE.SHJADDRM SHJADDRM , EAGLE.SGCHAKCM SGCHAKCM , EAGLE.SHJHAKJM SHJHAKJM , (SELECT * FROM EAGLE.SGCCODEM WHERE SUBSTR(CODE,1,2) = '05') SGCCODEM WHERE 1=1 AND DOMASTER.HAKBUN=SHJHAKJM.HAKBUN AND DOMASTER.HAKBUN=SHJADDRM.HAKBUN(+) AND SHJHAKJM.HAKGWA=SGCHAKCM.HAKGWA AND SHJHAKJM.HJSTATE = SGCCODEM.CODE(+) AND DOMASTER.STATE Between '1' And '6' AND DOMASTER.YEONDO = #{yeondo} AND DOMASTER.HAKGI = #{hakgi}
AND DOMASTER.DONG = #{dong}
ORDER BY DOMASTER.DONG, TO_NUMBER(DOMASTER.SIL), DOMASTER.SIL2

SELECT DOMASTER.DONG , DOMASTER.SIL , DOMASTER.SIL2 , SGCHAKCM.SORTKEY , SHJHAKJM.HAKGWA -- EAGLE 스키마 생략 가능 (FROM 절에 SHJHAKJM 으로 별칭 사용 시) , DOMASTER.HAKYEON , DOMASTER.HAKBUN , SHJHAKJM.IRUM -- EAGLE 스키마 생략 가능 , DOMASTER.DORMGBN , DECODE(DOMASTER.SEX, '1', '남', '2', '여') AS SEX , DOMASTER.IPGBN , SGCHAKCM.HAKGWAFNM , SHJADDRM.HSPOSTJUSO ||' '||SHJADDRM.HSJUSO AS HSPOSTJUSO , SHJADDRM.HSJUSO , DOMASTER.STATE , SGCCODEM.CDFNM AS HJSTATE , SUBSTR(SHJHAKJM.JUMINNO, 1, 6) AS JUMINNO -- EAGLE 스키마 생략 가능 , DOMASTER.BJUMSU , DOMASTER.BANKACC , SHJADDRM.HSTEL , SHJADDRM.HSBBTEL , DOMASTER.SEQ FROM EAGLE.DOMASTER DOMASTER , EAGLE.SHJHAKJM SHJHAKJM -- 라인 추가 , EAGLE.SHJADDRM SHJADDRM , EAGLE.SGCHAKCM SGCHAKCM , (SELECT * FROM EAGLE.SGCCODEM WHERE SUBSTR(CODE,1,2) = '05') SGCCODEM WHERE 1=1 AND DOMASTER.HAKBUN=EAGLE.SHJHAKJM.HAKBUN -- EAGLE.SHJHAKJM 으로 명확히 AND DOMASTER.HAKBUN=SHJADDRM.HAKBUN(+) AND EAGLE.SHJHAKJM.HAKGWA=SGCHAKCM.HAKGWA -- EAGLE.SHJHAKJM 으로 명확히 AND EAGLE.SHJHAKJM.HJSTATE = SGCCODEM.CODE(+) -- EAGLE.SHJHAKJM 으로 명확히 AND DOMASTER.STATE Between '1' And '6' AND DOMASTER.YEONDO = #{yeondo} AND DOMASTER.HAKGI = #{hakgi}
AND DOMASTER.DONG = #{dong} -- 선택한 동과, 전체 동에 대한 조건 설정
ORDER BY DOMASTER.DONG, TO_NUMBER(DOMASTER.SIL), DOMASTER.SIL2
